   120	/// Drop-in replacement for Lua's `os.execute` that applies mise's sanitized env
   121	/// (see [`apply_mise_env`]) and runs through the same shell as cmd.exec, while
   122	/// keeping `os.execute`'s streaming stdio (output goes to the terminal rather
   123	/// than being captured). Returns the process exit code (Lua 5.1 convention:
   124	/// `0` on success); `os.execute()` with no argument reports shell availability.
   125	/// (#10282)
   126	fn os_execute(lua: &Lua, command: Option<String>) -> LuaResult<i64> {
   127	    let Some(command) = command else {
   128	        // `os.execute()` with no argument: report that a shell is available.
   129	        return Ok(1);
   130	    };
   131	    let shell = cmd_shell(lua)?;
   132	    let mut cmd = command_from_shell(&shell, &command)?;
   133	    let has_mise_env = apply_mise_env(lua, &mut cmd)?;
   134	    debug!("[os.execute] command={command:?} shell={shell:?} has_mise_env={has_mise_env}");
   135	    let status = cmd
   136	        .status()
   137	        .map_err(|e| mlua::Error::RuntimeError(format!("Failed to execute command: {e}")))?;
   138	    Ok(status.code().unwrap_or(-1) as i64)
   139	}
