   141	fn cmd_shell(lua: &Lua) -> LuaResult<Vec<String>> {
   142	    if let Ok(shell) = lua.named_registry_value::<Table>("mise_cmd_shell") {
   143	        return shell.sequence_values::<String>().collect();
   144	    }
