   156	fn command_from_shell(shell: &[String], command: &str) -> LuaResult<Command> {
   157	    let (program, args) = shell.split_first().ok_or_else(|| {
   158	        mlua::Error::RuntimeError("cmd.exec shell command cannot be empty".to_string())
   159	    })?;
   160	    let mut cmd = Command::new(program);
   161	    cmd.args(args);
   162	    cmd.arg(command);
   163	    Ok(cmd)
